  /// @see avcodec_default_get_encode_buffer()
  ///
  /// - encoding: Set by libavcodec, user can override.
  /// - decoding: unused
  external ffi.Pointer<
    ffi.NativeFunction<
      ffi.Int Function(
        ffi.Pointer<AVCodecContext> s,
        ffi.Pointer<AVPacket> pkt,
