  @ffi.UnsignedInt()
  external int nb_side_data_prefer_packet;

  /// Array containing static side data, such as HDR10 CLL / MDCV structures.
  /// Side data entries should be allocated by usage of helpers defined in
  /// libavutil/frame.h.
  ///
