  external int cur_frame_start_index;

  @ffi.Array.multi([4])
  external ffi.Array<ffi.Int64> cur_frame_offset;

  @ffi.Array.multi([4])
  external ffi.Array<ffi.Int64> cur_frame_pts;

  @ffi.Array.multi([4])
  external ffi.Array<ffi.Int64> cur_frame_dts;

